We track two metrics during training:

Pixel Accuracy — the fraction of pixels correctly classified across all classes:\text{Pixel Accuracy} = \frac{\text{Correctly classified pixels}}{\text{Total pixels}}

Mean IoU (Intersection over Union) — the standard metric for segmentation quality. Computed for the 4 real terrain classes (excluding NULL) and averaged:\text{IoU}_c = \frac{TP_c}{TP_c + FP_c + FN_c} \qquad \text{mIoU} = \frac{1}{4} \sum_{c=0}^{3} \text{IoU}_c

SKIP_ID = "NLB_432655207EDR_F0160148NCAM00394M1"   # known bad file

def create_df(mask_path):
    """Walk mask_path, filter out frames where the rover is visible."""
    names = []
    for dirname, _, filenames in os.walk(mask_path):
        for filename in filenames:
            imname = filename.split('.')[0].replace("_merged", "")
            if imname == SKIP_ID:
                continue
            rover_path = MASK_ROVER + imname.replace("EDR", "MXY") + ".png"
            rover_raw  = cv2.imread(rover_path)
            if rover_raw is None:
                continue
            if (rover_raw[:, :, 0] == 1).any():
                continue
            names.append(imname)
    return pd.DataFrame({'id': names})

df = create_df(MASK_PATH)
print(f"Total usable images: {len(df)}")

_, X_val = train_test_split(df['id'].values, test_size=0.20, random_state=42)
print(f"Validation set size: {len(X_val)}")

def colorize(mask_2d):
    """Integer class mask (H,W) → RGB image (H,W,3) in [0,1]."""
    rgb = np.zeros((*mask_2d.shape, 3))
    for cls, color in enumerate(CLASS_COLORS):
        rgb[mask_2d == cls] = color
    return rgb


def denormalize(tensor):
    """Undo ImageNet normalisation → HWC float [0,1]."""
    mean = np.array([0.485, 0.456, 0.406])
    std  = np.array([0.229, 0.224, 0.225])
    img  = tensor.permute(1, 2, 0).cpu().numpy()
    return np.clip(std * img + mean, 0, 1)


def pixel_accuracy(preds_np, masks_np):
    return (preds_np == masks_np).sum() / masks_np.size


def mean_iou(preds_np, masks_np, num_classes=NUM_CLASSES):
    ious = []
    for cls in range(num_classes - 1):    # skip NULL
        inter = ((preds_np == cls) & (masks_np == cls)).sum()
        union = ((preds_np == cls) | (masks_np == cls)).sum()
        if union > 0:
            ious.append(inter / union)
    return float(np.mean(ious)) if ious else 0.0


